// Tests for module packs: `faraday pack list` + `faraday pack add`. Uses a real
// tmpdir lesson generated by the scaffold pipeline, no install.
import { test } from "node:test";
import assert from "node:assert/strict";
import fs from "node:fs/promises";
import path from "node:path";
import os from "node:os";
import { generateLesson } from "./generate.mjs";
import { runFaradayCli } from "./cli.mjs";
import { listPacks, installPack, removePack, resolvePack, validateManifest, validatePackDir, readManifestAt, readPackSkill, defaultPackNames, scaffoldPack } from "./pack.mjs";

/** Run the CLI capturing stdout/stderr (throws on non-zero). setExitCode is
 *  captured locally so a rejection test doesn't poison the runner's exit code. */
async function cli(args) {
  let out = "", err = "", code = 0;
  await runFaradayCli(args, {
    cwd: process.cwd(),
    stdout: (s) => (out += s),
    stderr: (s) => (err += s),
    setExitCode: (c) => (code = c),
    throwOnError: true,
  });
  return { out, err, code };
}

async function tmp() {
  return fs.mkdtemp(path.join(os.tmpdir(), "faraday-pack-test-"));
}
const read = (dir, rel) => fs.readFile(path.join(dir, rel), "utf8");
const exists = async (p) => !!(await fs.stat(p).catch(() => null));

test("listPacks includes all shipped packs", async () => {
  const packs = await listPacks();
  const names = packs.map((p) => p.name);
  for (const n of ["three", "tutor", "srs", "lecture-design", "audience", "exam", "slide-view", "textbook-view", "notes", "map2d", "game2d", "storybook-game2d", "sim2d", "stem-methods"]) {
    assert.ok(names.includes(n), `expected a \`${n}\` pack`);
  }
  assert.ok(!names.includes("kids"), "kids was folded into storybook-game2d");
  const sim2d = packs.find((p) => p.name === "sim2d");
  assert.ok(sim2d?.runtime?.dependencies?.gsap, "sim2d pins gsap");
  assert.equal(sim2d?.default, true, "sim2d is a default pack");
  const game2d = packs.find((p) => p.name === "game2d");
  assert.ok(game2d?.runtime?.dependencies?.["pixi.js"], "game2d pins pixi.js");
  assert.ok(game2d?.runtime?.dependencies?.["matter-js"], "game2d pins matter-js");
  assert.equal(game2d?.default, true, "game2d is a default pack");
  const story = packs.find((p) => p.name === "storybook-game2d");
  assert.deepEqual(story?.requires, ["game2d"], "storybook-game2d requires game2d");
  assert.equal(story?.default, true, "storybook-game2d is a default pack");
  // every shipped pack must have a valid manifest
  for (const p of packs) {
    const errs = validateManifest(await readManifestAt((await resolvePack(p.name)).packDir));
    assert.deepEqual(errs, [], `${p.name} manifest invalid: ${errs.join("; ")}`);
  }
  // every official pack declares a known category (drives `pack list` grouping)
  const CATEGORIES = new Set(["course", "lecture", "runtime", "methodology"]);
  for (const p of packs) {
    assert.ok(CATEGORIES.has(p.category), `${p.name} must have a known category, got ${p.category}`);
  }
  const three = packs.find((p) => p.name === "three");
  assert.ok(three.runtime?.dependencies?.["@faraday-academy/three"], "three pins its runtime pkg");
  assert.ok(three.runtime?.variants?.physics, "three exposes a physics variant");
  assert.ok(three.skill?.reference, "three ships a skill reference");
});

async function scaffold(name, { noDefaults = false } = {}) {
  const base = await tmp();
  const target = path.join(base, "lesson");
  await generateLesson({ targetDir: target, name, uuid: () => "fixed-id", noDefaults });
  return target;
}

test("installPack(tutor) drops the durable server + wiring", async () => {
  const target = await scaffold("Tutor Host");
  await installPack("tutor", { fromDir: target });

  const pkg = JSON.parse(await read(target, "package.json"));
  assert.equal(pkg.dependencies["@faraday-academy/tutor"], "0.2.0");
  for (const dep of ["ai", "@ai-sdk/workflow", "workflow", "nitro", "zod"]) {
    assert.ok(pkg.dependencies[dep], `server dep ${dep} missing`);
  }
  assert.ok(await exists(path.join(target, "api/chat.post.ts")), "nitro route copied");
  assert.ok(await exists(path.join(target, "workflows/tutor-agent.ts")), "workflow agent copied");
  assert.ok(await exists(path.join(target, "docs/tutor.md")), "tutor guide copied");
  assert.match(await read(target, "vite.config.ts"), /nitro|workflow/);
  assert.match(await read(target, "pnpm-workspace.yaml"), /nodeLinker:\s*hoisted/);
  assert.match(await read(target, "src/app.css"), /@faraday-academy\/tutor\/styles\.css/);
  assert.ok(await exists(path.join(target, ".faraday/packs/tutor/pack.md")), "skill installed");
});

