test("resolvePack classifies official names and local paths", async () => {
  const off = await resolvePack("three");
  assert.equal(off.name, "three");
  assert.equal(off.source, "three");
  assert.ok(await exists(path.join(off.packDir, "pack.json")));
  await assert.rejects(() => resolvePack("does-not-exist"), /Unknown pack/);

  // a local pack dir
  const base = await tmp();
  const packDir = path.join(base, "my-pack");
  await fs.mkdir(packDir, { recursive: true });
  await fs.writeFile(
    path.join(packDir, "pack.json"),
    JSON.stringify({ displayName: "Mine", skill: { reference: "g.md" } }),
  );
  await fs.writeFile(path.join(packDir, "g.md"), "# guide");
  const local = await resolvePack(packDir);
  assert.equal(local.packDir, packDir);
  assert.equal(local.source, packDir);
});

// Opt-in packs: shipped but NOT default. Presentations are a pick-one choice you
// add (`faraday pack add <name>`), unlike the batteries-included capability packs.
const OPT_IN_PACKS = ["map2d", "stem-methods"];

test("default packs: every capability pack is default, presentations are opt-in", async () => {
  const defaults = await defaultPackNames();
  const all = (await listPacks()).map((p) => p.name);
  const expectedDefaults = all.filter((n) => !OPT_IN_PACKS.includes(n));
  assert.deepEqual([...defaults].sort(), [...expectedDefaults].sort(), "capability packs default; opt-in packs not");
  for (const n of OPT_IN_PACKS) assert.ok(!defaults.includes(n), `${n} is opt-in, not default`);

  // folder skill (lecture-design) → multiple files
  const ld = await resolvePack("lecture-design");
  const ldFiles = await readPackSkill(ld.packDir, await readManifestAt(ld.packDir));
  assert.ok(ldFiles.length > 1, "lecture-design skill is a multi-file folder");
  assert.ok(ldFiles.every((f) => f.path.endsWith(".md") && typeof f.content === "string"));

  // file skill (audience) → single file
  const aud = await resolvePack("audience");
  const audFiles = await readPackSkill(aud.packDir, await readManifestAt(aud.packDir));
  assert.equal(audFiles.length, 1, "audience skill is a single file");
  assert.match(audFiles[0].content, /Audience/);
});

