test("pack show routes a folder skill via its entry, a sub-file, and --all", async () => {
  // folder skill with entry -> prints just the index (overview.md), plus a 'more' hint
  const idx = await cli(["pack", "show", "lecture-design"]);
  assert.match(idx.out, /overview/i, "printed the entry file");
  assert.match(idx.out, /more in this pack:/, "listed the sub-files to fetch");
  assert.doesNotMatch(idx.out, /Space and retrieve/, "did NOT dump the sub-files by default");

  // a specific sub-file
  const one = await cli(["pack", "show", "lecture-design", "spaced-retrieval.md"]);
  assert.match(one.out, /Space and retrieve/, "printed the requested sub-file");
  assert.doesNotMatch(one.out, /more in this pack:/, "no index hint when a file is requested");

  // --all concatenates every file with headers
  const all = await cli(["pack", "show", "lecture-design", "--all"]);
  assert.match(all.out, /===== overview.md =====/);
  assert.match(all.out, /===== spaced-retrieval.md =====/);

  // exam pack front door
  const exam = await cli(["pack", "show", "exam"]);
  assert.match(exam.out, /practice test/i, "exam SKILL.md is the entry");

  // unknown sub-file errors
  await assert.rejects(() => cli(["pack", "show", "exam", "nope.md"]), /no file/);
});

test("exam pack: folder skill with an index + sub-guides, skill-only", async () => {
  const exam = await resolvePack("exam");
  const manifest = await readManifestAt(exam.packDir);
  assert.equal(manifest.skill.entry, "SKILL.md");
  assert.deepEqual(manifest.runtime ?? {}, {}, "exam adds no runtime deps");
  const files = await readPackSkill(exam.packDir, manifest);
  const paths = files.map((f) => f.path);
  assert.ok(paths.includes("SKILL.md"), "has the index");
  assert.ok(paths.includes("blueprint.md") && paths.includes("scoring-feedback.md"), "has sub-guides");
  assert.deepEqual(validateManifest(manifest), [], "exam manifest is valid");
});

test("faraday new auto-installs every default pack, --no-defaults opts out", async () => {
  const withBase = await tmp();
  await generateLesson({ targetDir: path.join(withBase, "l"), name: "Def On", uuid: () => "id" });
  const prov = JSON.parse(await read(path.join(withBase, "l"), ".faraday/provenance.json"));
  const defaults = await defaultPackNames();
  assert.deepEqual([...prov.packs].sort(), [...defaults].sort(), "every default pack recorded");
  // opt-in packs (e.g. the map2d presentation) are shipped but NOT auto-installed
  assert.ok(!prov.packs.includes("map2d"), "opt-in map2d not auto-installed");
  assert.ok(await exists(path.join(withBase, "l", ".faraday/packs/audience/audience.md")), "audience skill installed");
  assert.ok(await exists(path.join(withBase, "l", ".faraday/packs/lecture-design/overview.md")), "lecture-design folder installed");
  // heavy runtime packs are defaults too now: three pins its R3F deps
  const pkg = JSON.parse(await read(path.join(withBase, "l"), "package.json"));
  assert.ok(pkg.dependencies["@faraday-academy/three"], "three (a default) pinned its runtime deps");

  const noDef = await tmp();
  await generateLesson({ targetDir: path.join(noDef, "l"), name: "Def Off", noDefaults: true, uuid: () => "id" });
  const prov2 = JSON.parse(await read(path.join(noDef, "l"), ".faraday/provenance.json"));
  assert.ok(!(prov2.packs ?? []).length, "no default packs with --no-defaults");
});

test("removePack un-registers a pack and reverses its unshared deps/css", async () => {
  const target = await scaffold("Remove Host");
  await installPack("three", { fromDir: target });
  assert.ok(await exists(path.join(target, ".faraday/packs/three/pack.md")), "installed first");

  const r = await removePack("three", { fromDir: target });
  assert.equal(r.manifestResolved, true);

  // skill half + pointer + provenance gone
  assert.equal(await exists(path.join(target, ".faraday/packs/three")), false, "skill dir removed");
  assert.ok(!(await read(target, "AGENTS.md")).includes("Pack `three`:"), "AGENTS.md pointer stripped");
  const prov = JSON.parse(await read(target, ".faraday/provenance.json"));
  assert.ok(!prov.packs.some((p) => (typeof p === "string" ? p : p.name).startsWith("three")), "provenance entry gone");

  // reversible runtime config reversed
  const pkg = JSON.parse(await read(target, "package.json"));
  assert.ok(!("@faraday-academy/three" in pkg.dependencies), "three dep removed");
  assert.ok(!(await read(target, "src/app.css")).includes("@faraday-academy/three/styles.css"), "three css removed");
  assert.ok(r.removedDeps.includes("@faraday-academy/three"));

  // copied files are reported, not deleted
  assert.ok(r.leftFiles.includes("docs/examples"));

  await assert.rejects(() => removePack("three", { fromDir: target }), /not installed/);
});

test("removePack keeps a dependency still required by another installed pack", async () => {
  const base = await tmp();
  const target = path.join(base, "lesson");
  await generateLesson({ targetDir: target, name: "Shared Deps", uuid: () => "fixed-id" });

  // a local pack that also depends on @react-three/fiber (shared with `three`)
  const packDir = path.join(base, "viz-pack");
  await fs.mkdir(packDir, { recursive: true });
  await fs.writeFile(
    path.join(packDir, "pack.json"),
    JSON.stringify({ displayName: "Viz", runtime: { dependencies: { "@react-three/fiber": "^9.0.0" } } }),
  );

  await installPack("three", { fromDir: target });
  await installPack("viz-pack", { fromDir: target, packDir, source: packDir });

  const r = await removePack("three", { fromDir: target });
  const pkg = JSON.parse(await read(target, "package.json"));
  assert.ok("@react-three/fiber" in pkg.dependencies, "shared dep kept");
  assert.ok(!("@faraday-academy/three" in pkg.dependencies), "unshared three dep removed");
  assert.ok(!r.removedDeps.includes("@react-three/fiber"), "shared dep not reported as removed");
});

test("installPack from an external (local) source records {name, source} in provenance", async () => {
  const base = await tmp();
  const target = path.join(base, "lesson");
  await generateLesson({ targetDir: target, name: "External Host", uuid: () => "fixed-id" });

  const packDir = path.join(base, "vocab-pack");
  await fs.mkdir(packDir, { recursive: true });
  await fs.writeFile(
    path.join(packDir, "pack.json"),
    JSON.stringify({ displayName: "Vocab", skill: { reference: "guide.md", loadWhen: "teaching vocab" } }),
  );
  await fs.writeFile(path.join(packDir, "guide.md"), "# vocab guide");

  const result = await installPack("vocab-pack", { fromDir: target, packDir, source: packDir });
  assert.equal(result.source, packDir);
  assert.ok(await exists(path.join(target, ".faraday/packs/vocab-pack/guide.md")), "skill installed");

  const prov = JSON.parse(await read(target, ".faraday/provenance.json"));
  const entry = prov.packs.find((p) => typeof p === "object" && p.name === "vocab-pack");
  assert.ok(entry, "external pack recorded as an object");
  assert.equal(entry.source, packDir);
});

test("pack new scaffolds each archetype with a folder skill + valid manifest", async () => {
  for (const kind of ["skill", "copy", "runtime"]) {
    const base = await tmp();
    const r = await scaffoldPack("demo-pack", { cwd: base, kind });
    assert.equal(r.kind, kind);
    assert.equal(r.skill, "folder", "default skill is a folder");
    // folder skill: an index that routes to sub-guides
    for (const f of ["pack.json", "skill/SKILL.md", "skill/using.md", "skill/pedagogy.md", "quality.md", "examples/demo-pack.tsx"]) {
      assert.ok(await exists(path.join(r.packDir, f)), `missing ${f}`);
    }
    assert.equal(
      await exists(path.join(r.packDir, "runtime/demo-pack/index.tsx")),
      kind === "copy",
      "copy archetype ships an author-editable component; others don't",
    );
    const manifest = await readManifestAt(r.packDir);
    assert.deepEqual(validateManifest(manifest), [], `${kind} manifest invalid`);
    assert.equal(manifest.default, true, "scaffolded packs are default (batteries-included)");
    assert.equal(manifest.skill?.reference, "skill", "skill points at the folder");
    assert.equal(manifest.skill?.entry, "SKILL.md", "folder skill declares an entry index");
  }
});

